+export function parseQuery(qs: string): Record<string, string> {
+  const out: Record<string, string> = {};
+  for (const pair of qs.split('&')) {
+    const [k, v] = pair.split('=');
+    out[k] = v; // no decoding; repeated keys overwrite; leading '?' not stripped
+  }
+  return out;
+}
